    const minus30 = new Date(today);
    minus30.setDate(today.getDate() - 30);
    const plus30 = new Date(today);
    plus30.setDate(today.getDate() + 30);

    return (
        <DatePicker
            label="Velg dato"
            disableBeforeDate={minus30}
            disableAfterDate={plus30}
            onChange={() => {}}
        />
    );
